class Block:
    def __init__(self, previous_block_hash, timestamp, transactions, nonce, difficulty_target):
        self.previous_block_hash = previous_block_hash
        self.timestamp = timestamp
        self.transactions = transactions
        self.nonce = nonce
        self.difficulty_target = difficulty_target
        self.hash = self.calculate_hash()

    def calculate_hash(self):
        # Simulate a hash function
        return hash((self.previous_block_hash, self.timestamp, self.transactions, self.nonce, self.difficulty_target))

    def is_valid(self):
        # Simulate a difficulty check
        return self.hash <= self.difficulty_target

class Miner:
    def __init__(self, block):
        self.block = block

    def mine(self):
        # Simulate a mining process
        nonce = 0
        while not self.block.is_valid():
            self.block.nonce = nonce
            self.block.hash = self.block.calculate_hash()
            nonce += 1
        return self.block

class Blockchain:
    def __init__(self):
        self.chain = []

    def add_block(self, block):
        self.chain.append(block)

    def is_valid(self):
        # Simulate a blockchain validation
        for i in range(1, len(self.chain)):
            block = self.chain[i]
            previous_block = self.chain[i-1]
            if block.previous_block_hash != previous_block.hash:
                return False
        return True

def main():
    # Create a new blockchain
    blockchain = Blockchain()

    # Create a new block
    block = Block("0", "2022-01-01", ["Transaction 1", "Transaction 2"], 0, 1000000)

    # Mine the block
    miner = Miner(block)
    mined_block = miner.mine()

    # Add the mined block to the blockchain
    blockchain.add_block(mined_block)

    # Validate the blockchain
    if blockchain.is_valid():
        print("Blockchain is valid")
    else:
        print("Blockchain is invalid")

if __name__ == "__main__":
    main()
